import{_ as a,o as t,c as e,a1 as r}from"./chunks/framework.BX4nIuL2.js";const u=JSON.parse('{"title":"移动机器人软硬件集成课程","description":"","frontmatter":{},"headers":[],"relativePath":"courses/mobile-robot.md","filePath":"courses/mobile-robot.md"}'),i={name:"courses/mobile-robot.md"};function s(l,o,n,c,h,p){return t(),e("div",null,[...o[0]||(o[0]=[r('<h1 id="移动机器人软硬件集成课程" tabindex="-1">移动机器人软硬件集成课程 <a class="header-anchor" href="#移动机器人软硬件集成课程" aria-label="Permalink to &quot;移动机器人软硬件集成课程&quot;">​</a></h1><p>本课程带你深入浅出地掌握现代移动机器人（Mobile Robots）的软硬件架构设计。我们将从最底层的电机控制、运动学建模，一直贯通到高层的 ROS2 导航与三维感知系统。</p><h2 id="_1-机器人运动学模型" tabindex="-1">1. 机器人运动学模型 <a class="header-anchor" href="#_1-机器人运动学模型" aria-label="Permalink to &quot;1. 机器人运动学模型&quot;">​</a></h2><p>在主流的移动机器人设计中，我们经常使用双轮差速（Differential Drive）和麦克纳姆轮（Mecanum Wheels）底盘：</p><ul><li><strong>双轮差速底盘:</strong> 结构简单，成本低廉，适用于室内平坦地面及扫地机器人等场景。</li><li><strong>麦克纳姆轮底盘:</strong> 具备全向平移能力，能在狭小空间内灵活转向。</li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>无论是何种构型，核心在于建立轮轴转速与机器人整体线速度、角速度之间的映射矩阵。 掌握<strong>移动机器人底盘的控制算法</strong>是确保机器人路径跟踪精度（如 Pure Pursuit 或 MPC 算法）的关键。</p></div><h2 id="_2-硬件控制链与-sophicar-仿真" tabindex="-1">2. 硬件控制链与 Sophicar 仿真 <a class="header-anchor" href="#_2-硬件控制链与-sophicar-仿真" aria-label="Permalink to &quot;2. 硬件控制链与 Sophicar 仿真&quot;">​</a></h2><p>在我们的实验平台中，推荐使用基于 ARM / RISC-V 的微控制器（如 STM32 或 Sophigo Duo）进行底盘运动控制。</p><ol><li><strong>电机驱动:</strong> 使用 H 桥驱动芯片，配合增量式霍尔编码器，实现速度 PID 闭环控制。</li><li><strong>三维底盘仿真:</strong> 开发者可以利用 Sophicar 仿真组件，在 Web 浏览器内直接渲染 3D 机器人车身，验证控制脉冲。</li></ol><hr><h2 id="_3-划词批注互动区" tabindex="-1">3. 划词批注互动区 <a class="header-anchor" href="#_3-划词批注互动区" aria-label="Permalink to &quot;3. 划词批注互动区&quot;">​</a></h2><p>如果您对本节运动学矩阵的推导或 Sophicar 电机引脚定义有任何疑问，请直接<strong>用鼠标划选目标文字</strong>，即可触发 Hypothesis 侧栏或本地批注面板。 如果您尚未登录，请先在弹窗中点击“去登录”，完成后即可发表您的见解与注释！</p>',12)])])}const d=a(i,[["render",s]]);export{u as __pageData,d as default};
